// Generate per-platform metadata using Claude Haiku via Anthropic API
const input = $input.first().json;
const topicId = input.topic_id;
const title = input.title || '';
const niche = input.niche || '';
const chapters = input.chapters || [];
const duration = input.duration || '2 hours';

const platforms = ['youtube', 'tiktok', 'instagram'];
const results = [];

for (const platform of platforms) {
  const prompt = `Generate optimized ${platform} metadata for this video.

VIDEO TOPIC: ${title}
DURATION: ${duration}
NICHE: ${niche}

Generate:
1. Title (max 60 chars, primary keyword, curiosity gap)
2. Description (${platform === 'youtube' ? 'first 2 lines hook + keyword, then summary, chapters with timestamps, hashtags' : platform === 'tiktok' ? 'punchy 1-2 sentences, trending hashtags' : 'storytelling hook, hashtag blocks'})
3. Tags/Hashtags (${platform === 'youtube' ? '15-20 tags, mix broad and specific' : '10-15 trending hashtags'})
4. Thumbnail text (max 4 words, high contrast, urgency/curiosity)

OUTPUT (JSON only, no preamble):
{ "title": "...", "description": "...", "tags": [...], "thumbnail_text": "..." }`;

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': process.env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        model: 'claude-3-5-haiku-20241022',
        max_tokens: 1024,
        messages: [{ role: 'user', content: prompt }],
      }),
    });

    const text = resp.content?.[0]?.text || '';
    let metadata;
    try {
      metadata = JSON.parse(text);
    } catch {
      // Try extracting JSON from markdown
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      metadata = jsonMatch ? JSON.parse(jsonMatch[0]) : { title, description: '', tags: [], thumbnail_text: '' };
    }

    // Store in platform_metadata table
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${process.env.SUPABASE_URL}/rest/v1/platform_metadata`,
      headers: {
        'apikey': process.env.SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal',
      },
      body: JSON.stringify({
        topic_id: topicId,
        platform: platform,
        title: metadata.title || title,
        description: metadata.description || '',
        tags: metadata.tags || [],
        hashtags: metadata.tags || [],
        thumbnail_text: metadata.thumbnail_text || '',
      }),
    });

    results.push({ platform, success: true, title: metadata.title });
  } catch (e) {
    results.push({ platform, success: false, error: e.message });
  }
}

return [{ json: { topic_id: topicId, results, all_success: results.every(r => r.success) } }];
